import{_ as d,o as a,c as r,ag as e}from"./chunks/framework.CxZWPeXl.js";const u=JSON.parse('{"title":"知識庫管理","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/admin-knowledge.md","filePath":"zh-TW/admin-knowledge.md"}'),l={name:"zh-TW/admin-knowledge.md"};function h(i,t,o,n,s,b){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="知識庫管理" tabindex="-1">知識庫管理 <a class="header-anchor" href="#知識庫管理" aria-label="Permalink to &quot;知識庫管理&quot;">​</a></h1><blockquote><p>上傳與管理文件資料，為知識助手提供精準的知識來源</p></blockquote><h2 id="概覽" tabindex="-1">概覽 <a class="header-anchor" href="#概覽" aria-label="Permalink to &quot;概覽&quot;">​</a></h2><p>知識庫管理功能讓管理員上傳、查看和刪除知識庫中的文件資料。這些資料會經過向量化處理，成為知識助手（RAG）的檢索來源，協助使用者在練習過程中查詢相關的銷售知識與產品資訊。</p><blockquote><p>此功能僅對具有知識庫管理權限的管理員開放。</p><p><strong>注意</strong>：目前知識庫管理主要透過後端 API 操作，前端管理介面尚在開發中。以下為功能說明，實際操作方式請依公司內部流程為準。</p></blockquote><hr><h2 id="文件上傳" tabindex="-1">文件上傳 <a class="header-anchor" href="#文件上傳" aria-label="Permalink to &quot;文件上傳&quot;">​</a></h2><h3 id="支援的檔案格式" tabindex="-1">支援的檔案格式 <a class="header-anchor" href="#支援的檔案格式" aria-label="Permalink to &quot;支援的檔案格式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>格式</th><th>副檔名</th><th>說明</th></tr></thead><tbody><tr><td>PDF</td><td>.pdf</td><td>包含文字、表格、圖片的完整文件</td></tr><tr><td>Word 文件</td><td>.docx</td><td>Microsoft Word 文件</td></tr><tr><td>純文字</td><td>.txt</td><td>純文字格式</td></tr><tr><td>HTML</td><td>.html</td><td>網頁格式文件</td></tr><tr><td>Markdown</td><td>.md</td><td>Markdown 格式文件</td></tr></tbody></table><h3 id="上傳流程" tabindex="-1">上傳流程 <a class="header-anchor" href="#上傳流程" aria-label="Permalink to &quot;上傳流程&quot;">​</a></h3><ol><li>進入文件上傳頁面</li><li>選擇要上傳的檔案</li><li>系統自動執行以下處理：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>文件解析 → 內容分塊 → 向量化嵌入 → 建立索引</span></span></code></pre></div><h3 id="自動處理說明" tabindex="-1">自動處理說明 <a class="header-anchor" href="#自動處理說明" aria-label="Permalink to &quot;自動處理說明&quot;">​</a></h3><table tabindex="0"><thead><tr><th>步驟</th><th>說明</th></tr></thead><tbody><tr><td>文件解析</td><td>解析文件內容，識別文字、表格與圖片</td></tr><tr><td>內容分塊</td><td>將文件內容拆分為適合檢索的小段落（Chunks）</td></tr><tr><td>向量化嵌入</td><td>將每個段落轉換為向量表示，用於語義搜尋</td></tr><tr><td>建立索引</td><td>將向量資料存入資料庫，供知識助手檢索使用</td></tr></tbody></table><h3 id="分塊類型" tabindex="-1">分塊類型 <a class="header-anchor" href="#分塊類型" aria-label="Permalink to &quot;分塊類型&quot;">​</a></h3><p>上傳後的文件會被分為以下三種類型的 Chunk：</p><table tabindex="0"><thead><tr><th>類型</th><th>說明</th></tr></thead><tbody><tr><td>TEXT</td><td>文字段落內容</td></tr><tr><td>TABLE</td><td>表格結構資料</td></tr><tr><td>IMAGE</td><td>圖片內容（以 Base64 編碼儲存）</td></tr></tbody></table><hr><h2 id="查看知識庫" tabindex="-1">查看知識庫 <a class="header-anchor" href="#查看知識庫" aria-label="Permalink to &quot;查看知識庫&quot;">​</a></h2><h3 id="文件列表" tabindex="-1">文件列表 <a class="header-anchor" href="#文件列表" aria-label="Permalink to &quot;文件列表&quot;">​</a></h3><p>管理員可查看已上傳至知識庫的所有文件分塊，每筆紀錄包含：</p><table tabindex="0"><thead><tr><th>欄位</th><th>說明</th></tr></thead><tbody><tr><td>文件名稱</td><td>原始上傳的文件名稱</td></tr><tr><td>公司</td><td>所屬公司（用於多租戶隔離）</td></tr><tr><td>部門</td><td>所屬部門</td></tr><tr><td>分塊類型</td><td>TEXT / TABLE / IMAGE</td></tr><tr><td>起始頁碼</td><td>此分塊在原始文件中的起始頁</td></tr><tr><td>結束頁碼</td><td>此分塊在原始文件中的結束頁</td></tr><tr><td>更新時間</td><td>最後更新的時間</td></tr><tr><td>建立者</td><td>上傳此文件的使用者</td></tr><tr><td>摘要</td><td>此分塊的文字摘要</td></tr><tr><td>原始文字</td><td>此分塊的完整原始內容（可選擇是否顯示）</td></tr></tbody></table><h3 id="篩選條件" tabindex="-1">篩選條件 <a class="header-anchor" href="#篩選條件" aria-label="Permalink to &quot;篩選條件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>條件</th><th>說明</th></tr></thead><tbody><tr><td>日期範圍</td><td>依更新時間篩選（起始日期 ~ 結束日期）</td></tr><tr><td>公司</td><td>篩選特定公司的資料</td></tr><tr><td>部門</td><td>篩選特定部門的資料</td></tr><tr><td>文件名稱</td><td>依文件名稱搜尋</td></tr><tr><td>分塊類型</td><td>篩選特定類型（TEXT / TABLE / IMAGE）</td></tr></tbody></table><h3 id="聚合分析" tabindex="-1">聚合分析 <a class="header-anchor" href="#聚合分析" aria-label="Permalink to &quot;聚合分析&quot;">​</a></h3><p>提供知識庫的統計概覽：</p><table tabindex="0"><thead><tr><th>指標</th><th>說明</th></tr></thead><tbody><tr><td>總分塊數</td><td>知識庫中所有分塊的總數量</td></tr><tr><td>總文件數</td><td>已上傳的不重複文件數量</td></tr></tbody></table><p>支援依以下維度分組統計：</p><ul><li>依公司分組</li><li>依部門分組</li><li>依文件名稱分組</li><li>依分塊類型分組</li></ul><hr><h2 id="刪除文件" tabindex="-1">刪除文件 <a class="header-anchor" href="#刪除文件" aria-label="Permalink to &quot;刪除文件&quot;">​</a></h2><p>管理員可批次刪除知識庫中的文件分塊。</p><h3 id="刪除操作" tabindex="-1">刪除操作 <a class="header-anchor" href="#刪除操作" aria-label="Permalink to &quot;刪除操作&quot;">​</a></h3><ol><li>使用篩選條件選定要刪除的分塊範圍</li><li>執行刪除操作</li><li>系統回報刪除結果： <ul><li>已刪除筆數</li><li>剩餘版本數</li><li>刪除時間</li></ul></li></ol><blockquote><p>刪除操作不可逆轉。刪除後，知識助手將無法再檢索到這些內容。</p></blockquote><hr><h2 id="多租戶隔離" tabindex="-1">多租戶隔離 <a class="header-anchor" href="#多租戶隔離" aria-label="Permalink to &quot;多租戶隔離&quot;">​</a></h2><p>知識庫採用嚴格的多租戶資料隔離機制：</p><ul><li>每份上傳的文件會自動關聯上傳者所屬的公司</li><li>使用者只能透過知識助手查詢到自己公司的知識庫內容</li><li>管理員只能管理自己權限範圍內的知識庫資料</li><li>不同公司之間的知識庫完全隔離，互不影響</li></ul><hr><h2 id="知識庫管理建議" tabindex="-1">知識庫管理建議 <a class="header-anchor" href="#知識庫管理建議" aria-label="Permalink to &quot;知識庫管理建議&quot;">​</a></h2><h3 id="內容規劃" tabindex="-1">內容規劃 <a class="header-anchor" href="#內容規劃" aria-label="Permalink to &quot;內容規劃&quot;">​</a></h3><table tabindex="0"><thead><tr><th>建議上傳的內容</th><th>說明</th></tr></thead><tbody><tr><td>產品資料</td><td>保險產品的詳細規格、條款、費率表</td></tr><tr><td>銷售話術</td><td>經過驗證的銷售話術與應對技巧</td></tr><tr><td>常見問題集</td><td>客戶常見問題與標準回答</td></tr><tr><td>公司規範</td><td>內部流程、合規要求、理賠規範</td></tr><tr><td>市場資訊</td><td>市場趨勢、競品比較、客戶案例</td></tr></tbody></table><h3 id="維護建議" tabindex="-1">維護建議 <a class="header-anchor" href="#維護建議" aria-label="Permalink to &quot;維護建議&quot;">​</a></h3><ol><li><strong>定期更新</strong> — 產品改版或政策變更時，及時更新對應文件</li><li><strong>清理過期資料</strong> — 定期刪除已過期或不再適用的內容</li><li><strong>格式優化</strong> — 上傳前整理文件格式，確保內容結構清晰</li><li><strong>分類管理</strong> — 使用有意義的檔案名稱，便於後續管理</li></ol><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>管理 <a href="./admin-prompts.html">Prompt 設定</a> 引導 AI 如何使用知識庫</li><li>設定 <a href="./admin-stages.html">銷售階段</a> 配合知識庫內容</li><li>管理 <a href="./admin-users.html">使用者帳號</a> 設定權限</li></ul>',48)])])}const p=d(l,[["render",h]]);export{u as __pageData,p as default};
